public interface CustomService {
    void initialize();
    void shutdown();
    boolean isAvailable();

    static CustomService getInstance() {
        return FabricLoader.getInstance().getEntrypoints("custom-service", CustomService.class)
            .stream()
            .findFirst()
            .orElseThrow(() -> new IllegalStateException("No CustomService implementation found"));
    }
}

public class SingletonManager {
    private static volatile SingletonManager instance;
    private final Map<String, Object> data = new ConcurrentHashMap<>();

    private SingletonManager() {}

    public static SingletonManager getInstance() {
        if (instance == null) {
            synchronized (SingletonManager.class) {
                if (instance == null) {
                    instance = new SingletonManager();
                }
            }
        }
        return instance;
    }
}

public interface ItemFactory {
    Item create(Item.Settings settings);

    class SwordFactory implements ItemFactory {
        private final ToolMaterial material;
        public SwordFactory(ToolMaterial material) { this.material = material; }
        @Override
        public Item create(Item.Settings settings) {
            return new SwordItem(material, 3, -2.4f, settings);
        }
    }

    class PickaxeFactory implements ItemFactory {
        private final ToolMaterial material;
        public PickaxeFactory(ToolMaterial material) { this.material = material; }
        @Override
        public Item create(Item.Settings settings) {
            return new PickaxeItem(material, 1, -2.8f, settings);
        }
    }
}

public class CustomItemBuilder {
    private int maxCount = 64;
    private boolean fireproof = false;
    private FoodComponent foodComponent = null;
    private Rarity rarity = Rarity.COMMON;

    public CustomItemBuilder maxCount(int maxCount) { this.maxCount = maxCount; return this; }
    public CustomItemBuilder fireproof() { this.fireproof = true; return this; }
    public CustomItemBuilder food(FoodComponent food) { this.foodComponent = food; return this; }
    public CustomItemBuilder rarity(Rarity rarity) { this.rarity = rarity; return this; }

    public Item build() {
        Item.Settings settings = new Item.Settings().maxCount(maxCount).rarity(rarity);
        if (fireproof) settings = settings.fireproof();
        if (foodComponent != null) settings = settings.food(foodComponent);
        return new Item(settings);
    }
}

public class EventBus<T> {
    private final List<Consumer<T>> listeners = new CopyOnWriteArrayList<>();

    public void register(Consumer<T> listener) {
        listeners.add(listener);
    }

    public void unregister(Consumer<T> listener) {
        listeners.remove(listener);
    }

    public void post(T event) {
        for (Consumer<T> listener : listeners) {
            listener.accept(event);
        }
    }
}

public class EnergyAdapter {
    public interface EnergyStorage {
        int getEnergy();
        int getMaxEnergy();
        void setEnergy(int energy);
    }

    public static class ItemStackEnergyAdapter implements EnergyStorage {
        private final ItemStack stack;

        public ItemStackEnergyAdapter(ItemStack stack) {
            this.stack = stack;
        }

        @Override
        public int getEnergy() {
            return stack.getOrDefault(ModDataComponentTypes.ENERGY, 0);
        }

        @Override
        public int getMaxEnergy() {
            return stack.getOrDefault(ModDataComponentTypes.MAX_ENERGY, 1000);
        }

        @Override
        public void setEnergy(int energy) {
            stack.set(ModDataComponentTypes.ENERGY, Math.min(energy, getMaxEnergy()));
        }
    }
}

public interface DamageStrategy {
    float calculateDamage(LivingEntity attacker, LivingEntity target, float baseDamage);

    class CriticalStrategy implements DamageStrategy {
        @Override
        public float calculateDamage(LivingEntity attacker, LivingEntity target, float baseDamage) {
            return attacker.getRandom().nextFloat() < 0.2f ? baseDamage * 2 : baseDamage;
        }
    }

    class ElementalStrategy implements DamageStrategy {
        @Override
        public float calculateDamage(LivingEntity attacker, LivingEntity target, float baseDamage) {
            if (target.isOnFire()) return baseDamage * 1.5f;
            return baseDamage;
        }
    }
}
